import java.io.File;
import java.io.FileWriter;
import java.io.IOException;
import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) throws IOException {
        // Assume this is user input received from a form or any other source
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly handling user input by encoding it before printing to the HTML response
        File file = new File("output.html");
        FileWriter writer = new FileWriter(file);

        writer.write("<html>");
        writer.write("<head><title>XSS Fixed</title></head>");
        writer.write("<body>");

        // Encode user input before printing to prevent XSS
        writer.write("<h1>Hello, " + Encode.forHtml(userInput) + "</h1>");

        writer.write("</body>");
        writer.write("</html>");

        writer.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
